#include <bits/stdc++.h>
using namespace std;

int n, m, k;
vector<int> a[505];

int main(){
    cin>>n>>m>>k;
    for(int i=1; i<=m; ++i){
        int x,y;
        cin>>x>>y;
        a[x].push_back(y);
        a[y].push_back(x);
    }
    for(int i=1; i<=n; i++){
        queue<int> q;
        q.push(i);
        for(int j=1; j<=k; j++){
            unordered_set<int> s; 
            while(q.size()){ 
                int c = q.front();
                q.pop();
                for(int i=0;i<a[c].size();i++){
                    s.insert(a[c][i]);
                }
            }
            cout << s.size() << ' ';
            for(int l : s){
                q.push(l); 
            }
        }
        cout<<"\n";
    }
    return 0;
}
